// Parse the LLM JSON output. Branch into success / failure rows so the
// caller can do conditional Supabase updates.

const inputItem = $input.first();
const llmText = inputItem.json.text || inputItem.json.output || '';

// Carry through the original webhook payload so we can write back to the right row.
const wh = $('Webhook').first().json.body;

function tryParse(raw) {
  if (!raw) return null;
  // Strip code fences if the model wrapped them despite the prompt.
  let s = String(raw).trim();
  if (s.startsWith('```')) {
    s = s.replace(/^```(?:json)?\s*/, '').replace(/```\s*$/, '').trim();
  }
  // First and last brace — defensive against any leading/trailing prose.
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first === -1 || last === -1 || last < first) return null;
  try {
    return JSON.parse(s.slice(first, last + 1));
  } catch (e) {
    return null;
  }
}

const parsed = tryParse(llmText);

function isValid(p) {
  return p
    && typeof p.greeting === 'string'
    && typeof p.opening === 'string'
    && Array.isArray(p.body_paragraphs)
    && p.body_paragraphs.every((x) => typeof x === 'string')
    && typeof p.closing === 'string';
}

if (parsed && isValid(parsed)) {
  return [{
    json: {
      ok: true,
      cover_letter_id: wh.cover_letter_id,
      letter_json: parsed,
    },
  }];
}

return [{
  json: {
    ok: false,
    cover_letter_id: wh.cover_letter_id,
    error_message: 'LLM output was not valid CoverLetterJson. Raw: ' + String(llmText).slice(0, 400),
  },
}];
